function App() {

  const [wrapper, setWrapper] = useState(true);

  const handleThemeChange = (props) => {
if (props === "Light") {
  setWrapper(true) }
   else {
  setWrapper(false)
  }
  console.log(wrapper)
}



  return (
    <>
      <div className={`${wrapper ? "Light" : "Dark"} ${!wrapper ? "Dark" : "Light"}`}>
        <ThemeChange change={handleThemeChange} />
